appsmith.onReady(() => {
  renderActionsAndExport();
});
appsmith.onModelChange(() => {
  renderActionsAndExport();
});
function renderActionsAndExport() {
  const data = appsmith.model;
  const recommendations = data.recommendations || [];
  const exportSample = data.export_sample || {};

  // 1. Render Recommendations List
  const listEl = document.getElementById('recommendation-list');
  listEl.innerHTML = "";
  if (recommendations.length === 0) {
    listEl.innerHTML = `<li><span style="color:#7f8c8d; font-style:italic;">No critical mitigations required at this time.</span></li>`;
  } else {
    recommendations.forEach(reco => {
      const li = document.createElement('li');

      // Assign border color class based on priority
      let borderClass = "reco-medium";
      let badgeClass = "badge-warning";
      if (reco.priority.toLowerCase() === "critical") {
        borderClass = "reco-critical";
        badgeClass = "badge-critical";
      } else if (reco.priority.toLowerCase() === "high") {
        borderClass = "reco-high";
        badgeClass = "badge-warning";
      }
      li.className = `reco-item ${borderClass}`;
      li.innerHTML = `
                <div class="reco-header">
                    <span class="badge ${badgeClass}">${reco.priority}</span>
                    <span class="reco-action">${reco.action}</span>
                </div>
                <div class="reco-evidence">Evidence pointer: ${reco.evidence}</div>
            `;
      listEl.appendChild(li);
    });
  }

  // 2. Render JSON Export Sample
  const previewBox = document.getElementById('json-preview-box');

  // Check if the object is empty
  if (Object.keys(exportSample).length === 0) {
    previewBox.textContent = "No export data available for current scan.";
  } else {
    // Pretty-print the JSON with 2 spaces for indentation
    previewBox.textContent = JSON.stringify(exportSample, null, 2);
  }
}

